import { Component, signal } from '@angular/core';

@Component({
  selector: 'app-counter',
  standalone: true,
  template: `
    <h2>Count: {{ count() }}</h2>
    <h2>Name: {{ user().name }}</h2>
    <h2>Tags: {{ tags().join(', ') }}</h2>

    <button (click)="count.set(0)">Reset</button>
    <button (click)="count.update(n => n + 1)">+1</button>
    <button (click)="count.update(n => n - 1)">-1</button>
    <button (click)="addTag('angular')">Add Tag</button>
    <button (click)="updateName()">Change Name</button>
  `,
})
export class CounterComponent {
  // ── Primitive signal ──────────────────────────────────────
  count = signal(0);

  // ── Object signal — TypeScript infers the type ───────────
  user = signal({ name: 'Ada', role: 'admin' });

  // ── Array signal ──────────────────────────────────────────
  tags = signal<string[]>(['typescript']);

  // ── set(): replace value entirely ────────────────────────
  resetCount(): void {
    this.count.set(0);
  }

  // ── update(): derive new value from current value ─────────
  increment(): void {
    this.count.update(n => n + 1);
  }

  updateName(): void {
    // Spread + update for objects — create a new object reference
    this.user.update(u => ({ ...u, name: 'Grace Hopper' }));
  }

  // ── Adding to an array — always return a new array ────────
  addTag(tag: string): void {
    this.tags.update(tags => [...tags, tag]);
  }

  removeTag(tag: string): void {
    this.tags.update(tags => tags.filter(t => t !== tag));
  }
}

import { Component, signal, computed } from '@angular/core';

interface CartItem { id: number; name: string; price: number; qty: number; }

@Component({
  selector: 'app-cart',
  standalone: true,
  template: `
    @for (item of items(); track item.id) {
      <div>
        {{ item.name }} × {{ item.qty }} = {{ item.price * item.qty | currency }}
      </div>
    }

    <hr />
    <p>Items in cart: {{ itemCount() }}</p>
    <p>Subtotal: {{ subtotal() | currency }}</p>
    <p>Tax (8%): {{ tax() | currency }}</p>
    <p><strong>Total: {{ total() | currency }}</strong></p>

    @if (isFreeShipping()) {
      <p class="badge">🎉 Free shipping!</p>
    } @else {
      <p>Add {{ amountToFreeShipping() | currency }} more for free shipping</p>
    }
  `,
})
export class CartComponent {
  items = signal<CartItem[]>([
    { id: 1, name: 'Angular Book',   price: 49.99, qty: 1 },
    { id: 2, name: 'TypeScript Mug', price: 12.99, qty: 2 },
  ]);

  // ── computed() — derived from items signal ─────────────────
  itemCount = computed(() =>
    this.items().reduce((sum, i) => sum + i.qty, 0)
  );

  subtotal = computed(() =>
    this.items().reduce((sum, i) => sum + i.price * i.qty, 0)
  );

  // ── computed() depending on another computed() ─────────────
  tax  = computed(() => this.subtotal() * 0.08);
  total = computed(() => this.subtotal() + this.tax());

  // ── Boolean derived signals ────────────────────────────────
  isFreeShipping = computed(() => this.subtotal() >= 50);
  amountToFreeShipping = computed(() =>
    Math.max(0, 50 - this.subtotal())
  );

  // ── Computed with filter / transformation ──────────────────
  expensiveItems = computed(() =>
    this.items().filter(i => i.price > 30)
  );

  updateQty(id: number, qty: number): void {
    this.items.update(list =>
      list.map(i => i.id === id ? { ...i, qty } : i)
    );
    // All computed signals that depend on items() recalculate automatically
  }
}

import { Component, signal, computed, effect, inject } from '@angular/core';
import { DOCUMENT } from '@angular/common';

@Component({
  selector: 'app-theme-demo',
  standalone: true,
  template: `
    <p>Theme: {{ theme() }}</p>
    <p>Font size: {{ fontSize() }}px</p>
    <input type="range" min="12" max="24"
           [value]="fontSize()"
           (input)="fontSize.set(+$any($event.target).value)" />
    <button (click)="toggleTheme()">Toggle Theme</button>
  `,
})
export class ThemeDemoComponent {
  private doc = inject(DOCUMENT);

  theme    = signal<'light' | 'dark'>('light');
  fontSize = signal(16);

  // ── effect(): sync theme to <html> class ──────────────────
  constructor() {
    effect(() => {
      // Reads theme() — runs whenever theme changes
      const isDark = this.theme() === 'dark';
      this.doc.documentElement.classList.toggle('dark', isDark);
      console.log('Theme changed to:', this.theme());
    });

    // ── effect(): sync fontSize to localStorage ────────────
    effect(() => {
      // Reads fontSize() — runs whenever fontSize changes
      localStorage.setItem('fontSize', this.fontSize().toString());
      this.doc.documentElement.style.fontSize = this.fontSize() + 'px';
    });

    // ── effect(): log ALL signal changes for debugging ─────
    effect(() => {
      console.log('State snapshot:', {
        theme:    this.theme(),
        fontSize: this.fontSize(),
      });
    });
  }

  toggleTheme(): void {
    this.theme.update(t => t === 'light' ? 'dark' : 'light');
    // effect() fires automatically — no manual call needed
  }
}

import { Component, input, output, computed } from '@angular/core';

interface Product { id: number; name: string; price: number; rating: number; }

@Component({
  selector: 'app-product-card',
  standalone: true,
  template: `
    <div [class.featured]="featured()">
      <h3>{{ product().name }}</h3>
      <p>{{ product().price | currency }}</p>

      <!-- computed() from input() — auto-updates when input changes -->
      <p>Stars: {{ stars() }}</p>
      <p>Category: {{ category() }}</p>

      @if (featured()) {
        <span class="badge">⭐ Featured</span>
      }

      <button (click)="addToCart.emit(product().id)">Add to Cart</button>
    </div>
  `,
})
export class ProductCardComponent {
  // ── Required input — parent MUST provide this ─────────────
  product  = input.required<Product>();

  // ── Optional inputs with defaults ─────────────────────────
  featured = input(false);              // default: false
  category = input('General');          // default: 'General'
  maxRating = input(5);                 // default: 5

  // ── output() — modern event emitter ───────────────────────
  addToCart = output<number>();

  // ── computed() FROM input() — works seamlessly ────────────
  stars = computed(() => {
    const ratio = this.product().rating / this.maxRating();
    const filled = Math.round(ratio * 5);
    return '★'.repeat(filled) + '☆'.repeat(5 - filled);
  });

  priceLabel = computed(() =>
    this.featured() ? '🔥 Hot deal: ' : 'Price: '
  );
}

