import { Component, signal, input, output } from '@angular/core';

// ── ✓ Modern: input() + output() ─────────────────────────
@Component({
  selector: 'app-toggle',
  standalone: true,
  template: `
    <button
      [class.on]="isOn()"
      (click)="toggle()"
    >
      {{ isOn() ? label() + ' ON' : label() + ' OFF' }}
    </button>
  `,
})
export class ToggleComponent {
  label    = input('Toggle');    // optional input with default
  initial  = input(false);       // starting value

  // output() — no EventEmitter or @Output decorator needed
  changed  = output<boolean>();  // emits the new state
  turnedOn = output();           // emits nothing (void)

  isOn = signal(false);

  constructor() {
    // Initialise from input — run once
    // Can't read input() in field initialiser, use effect or constructor
    // (input signals are not set until after construction)
  }

  toggle(): void {
    this.isOn.update(v => !v);
    this.changed.emit(this.isOn());   // emit the new value
    if (this.isOn()) this.turnedOn.emit();
  }
}

