import { Component, signal, inject } from '@angular/core';
import { HttpClient }    from '@angular/common/http';
import { toSignal, toObservable } from '@angular/core/rxjs-interop';
import {
  debounceTime, distinctUntilChanged, switchMap, catchError, of
} from 'rxjs';

interface Result { id: number; title: string; }

@Component({
  selector: 'app-search',
  standalone: true,
  template: `
    <input
      [value]="query()"
      (input)="query.set($any($event.target).value)"
      placeholder="Search..."
    />

    @if (results().loading) {
      <p>Searching...</p>
    } @else {
      @for (r of results().data; track r.id) {
        <p>{{ r.title }}</p>
      }
    }
  `,
})
export class SearchComponent {
  private http = inject(HttpClient);

  // ── Writable signal for the query ─────────────────────────
  query = signal('');

  // ── Convert signal → Observable to use RxJS operators ─────
  results = toSignal(
    toObservable(this.query).pipe(
      debounceTime(300),           // wait 300ms after user stops typing
      distinctUntilChanged(),      // skip if query didn't actually change
      switchMap(q =>
        q.length < 2
          ? of({ loading: false, data: [] })
          : this.http.get<Result[]>(`/api/search?q=${q}`).pipe(
              switchMap(data => of({ loading: false, data })),
              catchError(()  => of({ loading: false, data: [] }))
            )
      )
    ),
    { initialValue: { loading: false, data: [] as Result[] } }
  );
  // results is now a Signal<{ loading: boolean; data: Result[] }>
  // No async pipe, no subscribe(), no takeUntilDestroyed() needed
}

