import { Injectable, signal, computed } from '@angular/core';

export interface User { id: string; name: string; role: 'admin' | 'user'; }

@Injectable({ providedIn: 'root' })
export class AuthService {
  // ── Private writable signals — only this service writes ───
  private _user    = signal<User | null>(null);
  private _loading = signal(false);
  private _token   = signal<string | null>(null);

  // ── Public read-only — components can read, NOT write ─────
  readonly user    = this._user.asReadonly();    // Signal<User | null>
  readonly loading = this._loading.asReadonly(); // Signal<boolean>
  readonly isLoggedIn = computed(() => this._user() !== null);
  readonly isAdmin    = computed(() => this._user()?.role === 'admin');
  readonly userName   = computed(() => this._user()?.name ?? 'Guest');

  // ── Public API — the ONLY way to change state ─────────────
  async login(email: string, password: string): Promise<void> {
    this._loading.set(true);
    try {
      // ... call API, get token and user
      const { token, user } = await this.callLoginApi(email, password);
      this._token.set(token);
      this._user.set(user);
    } finally {
      this._loading.set(false);
    }
  }

  logout(): void {
    this._user.set(null);
    this._token.set(null);
  }

  getToken(): string | null {
    return this._token();
  }

  private async callLoginApi(e: string, p: string) {
    return { token: 'tok_123', user: { id: '1', name: 'Ada', role: 'admin' as const } };
  }
}

